class PostsSearch{constructor(){document.getElementById("search-input").onkeyup=e=>{"Enter"===e.key&&this.searchPosts()},document.getElementById("search-icon").onclick=()=>{this.searchPosts()}}searchPosts(){let e=document.getElementById("search-input");if(e.value){let t=new URLSearchParams;t.set("tags",e.value),location.href=`/posts/?${t.toString()}`}}}export{PostsSearch};